import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    waiting_time = 5

    next_node = None
    min_total_time = np.inf

    for node in unvisited_nodes:
        total_time = distance_matrix[current_node][node] + (
            np.sum(distance_matrix[truck_nodes]) / len(truck_nodes)
        ) + abs(distance_matrix[current_node][depot_node] - distance_matrix[node][depot_node]) + waiting_time

        if total_time < min_total_time:
            next_node = node
            min_total_time = total_time

    return next_node
